using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText);
}

namespace DocSummary.Services;

/// <summary>
/// Produces a concise summary by extracting the most representative sentences
/// from the input document using term-frequency scoring.
/// </summary>
public class ExtractiveSummarizer : IDocumentSummarizer
{
    private const int MaxSummarySentences = 3;

    private static readonly char[] SentenceDelimiters = ['.', '!', '?'];

    public string Summarize(string documentText)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= MaxSummarySentences)
        {
            return string.Join(" ", sentences);
        }

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scored sentences, preserving original order.
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(MaxSummarySentences)
            .Select(s => s.Index)
            .OrderBy(i => i)
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        var raw = text.Split(SentenceDelimiters, StringSplitOptions.RemoveEmptyEntries);
        var sentences = new List<string>();
        int pos = 0;

        foreach (var segment in raw)
        {
            var trimmed = segment.Trim();
            if (trimmed.Length == 0)
            {
                continue;
            }

            // Re-attach the original delimiter for readability.
            pos = text.IndexOf(trimmed, pos, StringComparison.Ordinal);
            int end = pos + trimmed.Length;
            char delimiter = end < text.Length && SentenceDelimiters.Contains(text[end])
                ? text[end]
                : '.';

            sentences.Add(trimmed + delimiter);
            pos = end;
        }

        return sentences;
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (freq.ContainsKey(word))
                    freq[word]++;
                else
                    freq[word] = 1;
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            var tokens = Tokenize(sentences[i]);
            double score = tokens.Count == 0
                ? 0
                : tokens.Sum(t => wordFrequencies.GetValueOrDefault(t, 0)) / (double)tokens.Count;

            scored.Add((i, score));
        }

        return scored;
    }

    private static List<string> Tokenize(string text)
    {
        return text
            .Split(' ', StringSplitOptions.RemoveEmptyEntries)
            .Select(w => new string(w.Where(char.IsLetterOrDigit).ToArray()))
            .Where(w => w.Length > 0)
            .ToList();
    }
}

